var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"부대원들을 도와 줘서 고맙다, 나유빈. 네가 아니었으면 큰 피해를 입었겠어.","JPN":"部隊員への協力に感謝する、イチノセ・カオル。\\n君がいなければ被害はもっと大きかっただろう。","ENG":"Thank you for helping my troops, Yubin. We would've suffered massive casualties if it weren't for you.","TWN":"謝謝你救了我的部隊，羅瑜斌。如果不是你，我們恐怕會遭受極大的損失。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 최전선에서 싸우고 있던 것 아니었나? 어떻게 여기에 나타난 거지?","JPN":"しかし、最前線で戦っていたはずではなかったのか？\\nどうやってここにやって来たのだ？","ENG":"But weren't you fighting on the front lines? What are you doing here?","TWN":"但你不是應該在最前線戰鬥嗎？為什麼會在這裡？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"최전선은 이미 무너졌습니다. 전멸 직전에 간신히 퇴각했죠.","JPN":"最前線はすでに崩壊しています。\\n全滅寸前に命からがら撤退してきました。","ENG":"We've already lost the front lines. We barely made it out before everyone got wiped out.","TWN":"最前線已經崩潰了，我們在全滅之前，好不容易才撤退掉。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"최대한 구하려고 했지만 생존자는 여기 있는 사람들이 전부입니다.","JPN":"可能な限り助けたかったのですが……\\n生存者はここにいる者で全員です。","ENG":"We tried our best to save as many folks as possible, but what you see here is all the survivors.","TWN":"雖然我盡可能地去救助其他人，但在這裡的就是全部的倖存者了。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그나마 제 6종 침식체들이 갑자기 어딘가로 사라지지 않았더라면 아무도 살아남지 못했을 겁니다.","JPN":"もし第6種侵食体たちが急にどこかに\\n消えてくれていなければ、誰一人として生き残れなかったでしょう。","ENG":"We wouldn't have made it either if the Category 6 C.O.s didn't suddenly run off somewhere.","TWN":"如果不是6類侵蝕體突然消失，我們應該不會有人能活下來吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"힐데 전대장은? 그 사람이 있었는데도 패배했다는 건가?","JPN":"ヒルデ戦隊長は？　あの人がいたのに敗北したというのか？","ENG":"What about Commander Hilde? You were defeated even with her around?","TWN":"希爾德隊長呢？有她在我們怎麼可能會戰敗？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"스승님은...... 현재 실종 상태입니다.","JPN":"師匠は……現在、行方不明になっています。","ENG":"Master... is currently MIA.","TWN":"師父……目前是失蹤狀態。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 실종이라니?","JPN":"なんだと？　どういうことだ？","ENG":"What? She's missing in action?","TWN":"什麼？你說失蹤？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"으으......","JPN":"うぅ……","ENG":"Ugh...","TWN":"呃呃……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"여긴...... 여긴 어디야......?","JPN":"ここは……ここ、どこ……？","ENG":"Where... Where am I?","TWN":"這是……這裡是哪裡……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연아! 정신이 들어?!","JPN":"キズナ！　気がついたのか！？","ENG":"Sooyeon! Have you come to?!","TWN":"秀妍！妳醒過來啦？！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"}}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이수연?!","JPN":"カナミ！？","ENG":"Lee Sooyeon?","TWN":"李秀妍？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"류드...... 밀라......?","JPN":"リュド……ミラ……？","ENG":"Lyud... mila?","TWN":"盧德……米拉……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너, 이게 대체 어떻게 된 거냐!","JPN":"カナミ、いったいなんてザマだ！","ENG":"What happened to you?","TWN":"妳、妳到底是怎麼回事？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리국 최강이라고 거들먹거리던 녀석이, 왜 이런 꼴로......!","JPN":"管理局最強だと威張っていた奴が、どうしてこんな姿に……！","ENG":"You were always bragging about being the best in the Administration... What happened?!","TWN":"妳不是老說自己是管理局最強制裁者嗎，怎麼會變成……！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_TIRED"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"아윽......!","JPN":"あぅっ……！","ENG":"Ngh!","TWN":"嗚啊……！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"전대장님, 수연이는 지금 중상을 입은 상태입니다.","JPN":"戦隊長、彼女は重症を負っています。","ENG":"Commander, Sooyeon has been heavily wounded.","TWN":"隊長，秀妍現在受了重傷。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"죄송하지만 질문은 나중에 해 주세요. 지금은 안정이 필요합니다.","JPN":"申し訳ないですが質問は後でお願いします。\\n今は安静にさせないと。","ENG":"I'd hate to be rude, but please save your questions for later. She needs to rest right now.","TWN":"雖然很抱歉，問題請妳之後再說吧，她現在需要休息。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};